def logPdf(request):
    mn = request.GET.get('dt')
    yr =  request.GET.get('yr')
    loc = request.GET.get('loc')
    
    data = LoggingSheet.objects.filter(month__year=yr, month__month=mn,city_location=loc)
    logging = LoggingSheet.objects.first()
    from fpdf import FPDF
    class PDFWithPageNumbers(FPDF):
        def header(self):
            
            self.set_y(0)
            self.set_x(0)
            self.image("static/assets/EnviTechAL LOGO.png", 16, 8, 16, 18)
            pdf.line(34,7,34,26.5)
          #   self.set_line_width(0.5)
          #   self.set_draw_color(26, 84, 26)
          #   self.line(0, 35, self.w, 35)
            font_path_alger = "static/fonts/ALGER.TTF"
            self.add_font("Algerian","",font_path_alger)
            self.set_font("Algerian","", 16)
            self.set_text_color(13, 46, 145)
            self.text(85,14,txt="ENVI TECH AL")
            font_path = "static/fonts/calibri.ttf"
            font_path_bold = "static/fonts/calibrib.ttf"
            self.add_font("Calibri", "B", "static/fonts/calibrib.ttf", uni=True)
            self.set_font("Calibri", "B", 15)
            self.set_text_color(25, 27, 28)
            self.text(76, 22, txt="SAMPLE LOGGING SHEET")
            self.set_font("Calibri", "B", 8)
            self.rect(170, 7, 30, 20, "D")
            self.text(172, 12, txt=logging.lab)  
            if logging.city_location == 'Lahore' or logging.city_location == 'lahore':                                                                                                                         
               self.text(172, 16, txt="Issue Date: 05-01-2023")
            elif logging.city_location == 'Karachi' or logging.city_location == 'karachi': 
                 self.text(172, 16, txt="Issue Date: 05-01-2023")
            self.text(172, 20, txt=logging.issue_no)
            
            pdf.set_text_color(0, 0, 0)
            self.alias_nb_pages()
            old_x = self.get_x()
            old_y = self.get_y()
            self.set_x(135)
            self.set_y(23)
            font_path = "static/fonts/calibri.ttf"
            font_path_bold = "static/fonts/calibrib.ttf"
            pdf.add_font("Calibri","",font_path,uni=True)
            pdf.add_font("Calibri","B",font_path_bold,uni=True)
            page_number = f"{self.page_no()}s: of {{nb}}"
            self.set_font("Calibri","B", 8)
            self.text(172,24,txt="Page No:")
            self.set_font("Calibri","B", 8)
          #   self.line(175,41,178+self.get_string_width(page_number),41)
            self.cell(self.w - 25, 0, f'{self.page_no()} of {{nb}}',border=False, align='R')
            self.set_x(old_x)
            self.set_y(old_y)
            self.rect(10,7,190,20)

            pdf.rect(10,27,190,6)
            pdf.text(12,31,txt="Month:")
            for i in data:
               month = i.month.strftime("%B")
               
               if month == 'January':
                    pdf.text(22, 31, txt="January")
               elif month == 'February':
                    pdf.text(22, 31, txt="February")
               elif month == 'March':
                    pdf.text(22, 31, txt="March")
               elif month == 'April':
                    pdf.text(22, 31, txt="April")
               elif month == 'May':
                    pdf.text(22, 31, txt="May")
               elif month == 'June':
                    pdf.text(22, 31, txt="June")
               elif month == 'July':
                    pdf.text(22, 31, txt="July")
               elif month == 'August':
                    pdf.text(22, 31, txt="August")
               elif month == 'September':
                    pdf.text(22, 31, txt="September")
               elif month == 'October':
                    pdf.text(22, 31, txt="October")
               elif month == 'November':
                    pdf.text(22, 31, txt="November")
               elif month == 'December':
                    pdf.text(22, 31, txt="December")
               break
            pdf.set_y(33)
    pdf = PDFWithPageNumbers()
    pdf.add_page()
    font_path = "static/fonts/calibri.ttf"
    font_path_bold = "static/fonts/calibrib.ttf"
    pdf.add_font("Calibri","",font_path,uni=True)
    pdf.add_font("Calibri","B",font_path_bold,uni=True)
    pdf.set_font("Calibri","", 5)
    

    # Add table headers
    headers = [
        ["s.No", "Sample/ Test ID", "Client Name", "Address", "Name of Attention Person", "Contact Detail/Email Address",
        "Nature of Sample/Test", "Receiving Date", "Expected Reported Date", "Reporting Date", "Received By", "Remarks"
    ],]
    sr =1
    # Add table rows
    for log in data:
        if log.sample_id:
            a = [
                str(sr),log.sample_id, log.client_name, log.address, log.att_person, log.email, log.sample_nature,
                log.rec_date, log.exp_date, log.rep_date, log.rec_by, log.remarks
            ]
            sr+=1
            
            headers.append(a)

    with pdf.table(col_widths=(8, 15, 17, 30, 15, 40, 20, 20, 20, 20, 18, 14),
                  line_height=3, text_align=("CENTER", "CENTER", "CENTER", "CENTER", 'CENTER', 'CENTER', "CENTER",
                                             "CENTER", "CENTER", "CENTER", 'CENTER', 'CENTER')) as table:
        for data_row in headers:
            row = table.row()
            for datum in data_row:
                row.cell(datum)
    
    # Create a response object
    response = HttpResponse(content_type='application/pdf')
    response['Content-Disposition'] = f'inline; filename={logging.lab}.pdf'

    # Output the PDF to the response
    pdf_output = BytesIO()
    pdf_output.write(pdf.output(dest='S'))
    response.write(pdf_output.getvalue())

    return response



